import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it.todo("should quote a sword for a new customer (base premium + processing fee + 10% first insurance surcharge)");
    it.todo("should quote an amulet for a new customer");
    it.todo("should quote a staff for a new customer");
    it.todo("should quote a potion for a new customer");
    it.todo("should quote a single component (rune) at 25 G base premium");
    it.todo("should quote a single moonstone component");
    it.todo("should quote 3 alike components as a building block at 60 G");
    it.todo("should quote multiple items by summing base premiums");
    it.todo("should add 50% risk surcharge for cursed items");
    it.todo("should add 30% risk surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should round amounts up in MHPCO's favor (whole G)");
  });

  describe("Processing a claim", () => {
    it.todo("should pay out damage minus 100 G deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to highly enchanted items (>= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should report remaining cap after each claim");
  });

  describe("CLI scenario processing", () => {
    it.todo("should process schema example 1 (quote only) and produce a results array");
    it.todo("should process schema example 2 (quote followed by two claims)");
  });
});

