export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface ClaimDamage {
  itemType: string;
  amount: number;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: ClaimDamage[] };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const basePremiumFor = (itemType: string): number => {
  if (COMPONENT_TYPES.has(itemType)) return COMPONENT_BASE_PREMIUM;
  return MAIN_ITEM_BASE_PREMIUMS[itemType];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const ceilG = (amount: number): number => Math.ceil(Math.round(amount * 100) / 100);

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const item = step.items[0];
      const basePremium = basePremiumFor(item.type);
      const withSurcharge = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
      return { premium: ceilG(withSurcharge + PROCESSING_FEE) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

