const BUILDING_BLOCK_SIZE = 3;
const BUILDING_BLOCK_PREMIUM = 60;

const basePremiumFor = (itemType: string): number => {
  if (COMPONENT_TYPES.has(itemType)) return COMPONENT_BASE_PREMIUM;
  return MAIN_ITEM_BASE_PREMIUMS[itemType];
};

const sumBasePremium = (items: Item[]): number => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [type, count] of counts) {
    if (COMPONENT_TYPES.has(type)) {
      const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
      const loose = count % BUILDING_BLOCK_SIZE;
      total += blocks * BUILDING_BLOCK_PREMIUM + loose * COMPONENT_BASE_PREMIUM;
    } else {
      total += count * basePremiumFor(type);
    }
  }
  return total;
};

