export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface ClaimDamage {
  itemType: string;
  amount: number;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: ClaimDamage[] };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const BUILDING_BLOCK_SIZE = 3;
const BUILDING_BLOCK_PREMIUM = 60;

const componentGroupPremium = (count: number): number => {
  const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
  const loose = count % BUILDING_BLOCK_SIZE;
  return blocks * BUILDING_BLOCK_PREMIUM + loose * COMPONENT_BASE_PREMIUM;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumBasePremium = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    if (COMPONENT_TYPES.has(type)) {
      total += componentGroupPremium(count);
    } else {
      total += count * MAIN_ITEM_BASE_PREMIUMS[type];
    }
  }
  return total;
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const ceilG = (amount: number): number => Math.ceil(Math.round(amount * 100) / 100);

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const basePremium = sumBasePremium(step.items);
      const withSurcharge = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
      return { premium: ceilG(withSurcharge + PROCESSING_FEE) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

