const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

interface Policy {
  items: Item[];
  remainingCap: number;
}

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies = new Map<number, Policy>();
  const results = scenario.steps.map((step, stepIndex) => {
    if (step.op === "quote") {
      const premium = computePremium(step.items, scenario.customer, quoteCount);
      quoteCount += 1;
      const insuranceSum = sumInsuranceValue(step.items);
      policies.set(stepIndex, { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSum });
      return { premium };
    }
    const policy = policies.get(step.policy)!;
    const totalDamage = step.incident.damages.reduce((sum, d) => sum + d.amount, 0);
    const payout = totalDamage - DEDUCTIBLE;
    policy.remainingCap -= payout;
    return { payout, remainingCap: policy.remainingCap };
  });
  return { results };
};

