const findInsuredItem = (damage: ClaimDamage, policy: Policy): Item | undefined =>
  policy.items.find((it) => it.type === damage.itemType);

const isDragonMaterial = (item: Item | undefined): boolean =>
  item?.material === DRAGON_MATERIAL;

