1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface ClaimDamage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: { cause: string; damages: ClaimDamage[] };
26	}
27	
28	export type Step = QuoteStep | ClaimStep;
29	
30	export interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	export interface QuoteResult {
36	  premium: number;
37	}
38	
39	export interface ClaimResult {
40	  payout: number;
41	  remainingCap: number;
42	}
43	
44	export type StepResult = QuoteResult | ClaimResult;
45	
46	export interface ScenarioResult {
47	  results: StepResult[];
48	}
49	
50	const COMPONENT_BASE_PREMIUM = 25;
51	const COMPONENT_INSURANCE_VALUE = 250;
52	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
53	
54	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
55	  sword: 100,
56	  amulet: 60,
57	  staff: 80,
58	  potion: 40,
59	};
60	
61	const MAIN_ITEM_INSURANCE_VALUES: Record<string, number> = {
62	  sword: 1000,
63	  amulet: 600,
64	  staff: 800,
65	  potion: 400,
66	};
67	
68	const insuranceValueFor = (itemType: string): number => {
69	  if (COMPONENT_TYPES.has(itemType)) return COMPONENT_INSURANCE_VALUE;
70	  return MAIN_ITEM_INSURANCE_VALUES[itemType];
71	};
72	
73	const sumInsuranceValue = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
75	
76	const BUILDING_BLOCK_SIZE = 3;
77	const BUILDING_BLOCK_PREMIUM = 60;
78	
79	const componentGroupPremium = (count: number): number => {
80	  const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
81	  const loose = count % BUILDING_BLOCK_SIZE;
82	  return blocks * BUILDING_BLOCK_PREMIUM + loose * COMPONENT_BASE_PREMIUM;
83	};
84	
85	const CURSED_SURCHARGE = 0.5;
86	const HIGH_ENCHANTMENT_THRESHOLD = 5;
87	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
88	
89	const isHighlyEnchanted = (item: Item): boolean =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
91	
92	const itemRiskMultiplier = (item: Item): number => {
93	  let surcharge = 0;
94	  if (item.cursed) surcharge += CURSED_SURCHARGE;
95	  if (isHighlyEnchanted(item)) surcharge += HIGH_ENCHANTMENT_SURCHARGE;
96	  return 1 + surcharge;
97	};
98	
99	const sumBasePremium = (items: Item[]): number => {
100	  const componentCounts = new Map<string, number>();
101	  let mainItemTotal = 0;
102	  for (const item of items) {
103	    if (COMPONENT_TYPES.has(item.type)) {
104	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
105	    } else {
106	      mainItemTotal += MAIN_ITEM_BASE_PREMIUMS[item.type] * itemRiskMultiplier(item);
107	    }
108	  }
109	  let total = mainItemTotal;
110	  for (const [, count] of componentCounts) {
111	    total += componentGroupPremium(count);
112	  }
113	  return total;
114	};
115	
116	const PROCESSING_FEE = 5;
117	const FIRST_INSURANCE_SURCHARGE = 0.1;
118	const SUBSEQUENT_CONTRACT_DISCOUNT = 0.15;
119	const LOYALTY_THRESHOLD_YEARS = 2;
120	const LOYALTY_DISCOUNT = 0.2;
121	
122	const ceilG = (amount: number): number => Math.ceil(Math.round(amount * 100) / 100);
123	
124	const loyaltyMultiplierFor = (customer: Customer): number =>
125	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? 1 - LOYALTY_DISCOUNT : 1;
126	
127	const contractMultiplier = (contractIndex: number): number =>
128	  contractIndex === 0
129	    ? 1 + FIRST_INSURANCE_SURCHARGE
130	    : 1 - SUBSEQUENT_CONTRACT_DISCOUNT;
131	
132	const computePremium = (items: Item[], customer: Customer, contractIndex: number): number => {
133	  const basePremium = sumBasePremium(items);
134	  const afterContractAdjustment = basePremium * contractMultiplier(contractIndex);
135	  const afterLoyalty = afterContractAdjustment * loyaltyMultiplierFor(customer);
136	  return ceilG(afterLoyalty + PROCESSING_FEE);
137	};
138	
139	const DEDUCTIBLE = 100;
140	const CAP_MULTIPLIER = 2;
141	const ENCHANTMENT_PAYOUT_THRESHOLD = 8;
142	const ENCHANTMENT_PAYOUT_RATE = 0.5;
143	
144	const reimbursableDamage = (item: Item, damageAmount: number): number => {
145	  if ((item.enchantment ?? 0) >= ENCHANTMENT_PAYOUT_THRESHOLD) {
146	    return damageAmount * ENCHANTMENT_PAYOUT_RATE;
147	  }
148	  return damageAmount;
149	};
